 using System.ComponentModel;
 using System.Text;
 using System.Text.Json;
 using Microsoft.Extensions.Logging;
 using ModelContextProtocol.Server;

 namespace ApiMcpServer.Tools;

 /// <summary>
 /// MCP tools that wrap the JSONPlaceholder REST API.
 /// HttpClient and ILogger are injected via constructor DI —
 /// the SDK resolves them automatically and they never appear in the tool schema.
 /// </summary>
 [McpServerToolType]
 public class JsonPlaceholderTools(HttpClient httpClient, ILogger<JsonPlaceholderTools> logger)
 {
     private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

     [McpServerTool, Description("Get a post by its numeric ID from the REST API.")]
     public async Task<string> GetPost(
         [Description("The numeric ID of the post to retrieve (1-100).")] int postId,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching post {PostId}", postId);
         var response = await httpClient.GetAsync($"/posts/{postId}", cancellationToken);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync(cancellationToken);
         return FormatJson(json);
     }

     [McpServerTool, Description("List posts, optionally filtered by user ID.")]
     public async Task<string> ListPosts(
         [Description("Filter posts to this user ID. Omit to list all posts.")] int? userId = null,
         CancellationToken cancellationToken = default)
     {
         var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
         logger.LogInformation("Listing posts: {Url}", url);
         var response = await httpClient.GetAsync(url, cancellationToken);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync(cancellationToken);
         return FormatJson(json);
     }

     [McpServerTool, Description("Create a new post with the given title, body, and user ID.")]
     public async Task<string> CreatePost(
         [Description("Title of the new post.")] string title,
         [Description("Body text of the new post.")] string body,
         [Description("User ID of the post author.")] int userId,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Creating post for user {UserId}", userId);
         var payload = JsonSerializer.Serialize(new { title, body, userId });
         var content = new StringContent(payload, Encoding.UTF8, "application/json");
         var response = await httpClient.PostAsync("/posts", content, cancellationToken);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync(cancellationToken);
         return FormatJson(json);
     }

     [McpServerTool, Description("Get all comments for a specific post.")]
     public async Task<string> GetComments(
         [Description("The post ID whose comments to retrieve.")] int postId,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching comments for post {PostId}", postId);
         var response = await httpClient.GetAsync($"/posts/{postId}/comments", cancellationToken);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync(cancellationToken);
         return FormatJson(json);
     }

     private static string FormatJson(string json)
     {
         using var doc = JsonDocument.Parse(json);
         return JsonSerializer.Serialize(doc, JsonOptions);
     }
 }
